    [Fact]
    public void LoadYamlInput()
    {
        string yamlData = """
id: chk_abc123
sessionId: sess_abc123
turnId: turn_001
checkpointNumber: 3
title: Added harness contracts
createdAt: "2026-06-09T20:00:00Z"

""";

        var instance = Checkpoint.FromYaml(yamlData);

        Assert.NotNull(instance);
        Assert.Equal("chk_abc123", instance.Id);
        Assert.Equal("sess_abc123", instance.SessionId);
        Assert.Equal("turn_001", instance.TurnId);
        Assert.Equal(3, instance.CheckpointNumber);
        Assert.Equal("Added harness contracts", instance.Title);
        Assert.Equal("2026-06-09T20:00:00Z", instance.CreatedAt);
    }

