    [Fact]
    public void RoundtripJson()
    {
        // Test that FromJson -> ToJson -> FromJson produces equivalent data
        string jsonData = """
{
  "id": "chk_abc123",
  "sessionId": "sess_abc123",
  "turnId": "turn_001",
  "checkpointNumber": 3,
  "title": "Added harness contracts",
  "createdAt": "2026-06-09T20:00:00Z"
}
""";

        var original = Checkpoint.FromJson(jsonData);
        Assert.NotNull(original);

        var json = original.ToJson();
        Assert.False(string.IsNullOrEmpty(json));

        var reloaded = Checkpoint.FromJson(json);
        Assert.NotNull(reloaded);
        Assert.Equal("chk_abc123", reloaded.Id);
        Assert.Equal("sess_abc123", reloaded.SessionId);
        Assert.Equal("turn_001", reloaded.TurnId);
        Assert.Equal(3, reloaded.CheckpointNumber);
        Assert.Equal("Added harness contracts", reloaded.Title);
        Assert.Equal("2026-06-09T20:00:00Z", reloaded.CreatedAt);
    }

